/* jquery.dropotron.min.js | minimal version for navigation menus */
(function($){$.fn.dropotron=function(opts){var settings=$.extend({offsetX:0,offsetY:0,expandable:false,hideDelay:150},opts||{});var active=null,hoverTimer=null;this.find('> .submenu').each(function(){var $$=$(this),$o=$$.children('a').first(),$s=$$.children('ul').first(),w=$o.outerWidth(),h=$o.outerHeight(),hidden=false;$o.append('<span class="toggle"></span>');$s.addClass('submenu').css({position:'absolute',top:'100%',left:settings.offsetX+'px',minWidth:w+'px'});$$.addClass('dropdown').on('mouseenter',function(){if(hidden){$s.stop(true,true).fadeIn(200);hidden=false}clearTimeout(hoverTimer);if(active&&active[0]!==$$[0])active.dropotron('hide');active=$$;$$ .addClass('active');$s.css({display:'block'})}).on('mouseleave',function(){$s.stop(true,true);hoverTimer=setTimeout(function(){$s.fadeOut(150);$$.removeClass('active');hidden=true;active=null},settings.hideDelay)})});return this}})(jQuery);
